   216→                  transition={{ delay: 0.24 }}
   217→                  style={{
   218→                    display: "flex",
   219→                    flexDirection: "column",
   220→                    alignItems: "center",
   221→                    marginBottom: 36,
   222→                    gap: 6,
   223→                  }}
   224→                >
   225→                  <span
   226→                    style={{
   227→                      fontFamily: "monospace",
   228→                      fontSize: 38,
   229→                      fontWeight: 700,
   230→                      color: msLeft < 60_000 ? "#ef4444" : msLeft < 300_000 ? "#f97316" : "#facc15",
   231→                      letterSpacing: "0.05em",
   232→                      lineHeight: 1,
   233→                    }}
   234→                    data-testid="admin-alert-countdown"
   235→                  >
   236→                    {formatCountdown(msLeft)}
   237→                  </span>
   238→                  <span style={{ color: "rgba(255,255,255,0.4)", fontSize: 11, letterSpacing: "0.08em", textTransform: "uppercase" }}>
   239→                    until account lock
   240→                  </span>
   241→                </motion.div>
   242→              )}
   243→            </>
   244→          )}
   245→
   246→          {!isExpired && (
   247→            <p style={{ color: "rgba(255,255,255,0.35)", fontSize: 12, marginTop: 8 }}>
   248→              Tap ✕ to dismiss
   249→            </p>
   250→          )}
   251→        </motion.div>
   252→      )}
   253→    </AnimatePresence>
   254→  );
   255→}
